/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // The problem can be modeled as a multi-source Breadth-First Search (BFS).
    // Since we are interested in the *first* time a cell is reached, and the
    // rule for simultaneous arrival is "take the maximum color", we need to
    // track not just the distance, but also the color and the time it arrives.

    // Initialize the grid with -1 (or 0 if 0 means uncolored, but since colors >= 1, -1 is safer for 'unreached')
    // We will use the grid to store the final color.
    const grid = Array(n).fill(0).map(() => Array(m).fill(0));

    // A custom queue structure for BFS: [r, c, color, time]
    const queue = [];

    // 1. Initialize sources
    for (const [r, c, color] of sources) {
        grid[r][c] = color;
        // Time starts at 0 for initial sources
        queue.push({ r: r, c: c, color: color, time: 0 });
    }

    const directions = [
        [0, 1], [0, -1], [1, 0], [-1, 0] // Right, Left, Down, Up
    ];

    // 2. Multi-source BFS
    // Since multiple colors can reach a cell at the same time, or one color
    // reaches it at time T and another reaches it at time T+1, we need
    // a mechanism to compare arrival times and colors correctly.

    // A standard BFS guarantees finding the shortest time.
    // We need to process levels (time steps) explicitly to handle simultaneous arrivals correctly.

    let head = 0;
    while (head < queue.length) {
        const current = queue[head++];
        const { r, c, color, time } = current;

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;
            const nextTime = time + 1;

            // Check boundaries
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                // Check if the cell is uncolored OR if the current path offers a better result.

                // If grid[nr][nc] is 0, it means it's uncolored (since colors >= 1).
                if (grid[nr][nc] === 0) {
                    // Cell is uncolored, it will be colored by this expansion.
                    // Since this is BFS, this is the earliest time it can be colored.
                    grid[nr][nc] = color;
                    queue.push({ r: nr, c: nc, color: color, time: nextTime });
                } else {
                    // Cell is already colored. We need to compare the arrival time and color.
                    // This standard BFS structure doesn't easily track the arrival time of the existing color.
                    // We need to augment the grid to store (color, time_of_arrival).

                    // Let's redefine the state management. Instead of just using grid[r][c] for color,
                    // we use a separate structure to track the best arrival info.
                    // Since we only care about the *final* state, we only need to process neighbors
                    // if the current path is better than what is already established for (nr, nc).

                    // A pure BFS inherently handles "earliest arrival time" first.
                    // If grid[nr][nc] is already set, it means it was colored by *some* source
                    // at *some* time T_old.

                    // If T_new < T_old, we update.
                    // If T_new == T_old, we update if Color_new > Color_old.

                    // To implement this correctly, the queue must store time, and the grid must store (color, time).
                }
            }
        }
    }

    // --- RESTARTING with proper state tracking for time and color ---

    // State: [color, time_of_arrival]
    // Initialize with [0, Infinity] representing uncolored/unreached.
    const finalState = Array(n).fill(0).map(() => Array(m).fill(0).map(() => [0, Infinity]));

    const newQueue = [];

    for (const [r, c, color] of sources) {
        finalState[r][c] = [color, 0];
        newQueue.push({ r: r, c: c, color: color, time: 0 });
    }

    let head_bfs = 0;
    while (head_bfs < newQueue.length) {
        const { r, c, color: current_color, time: current_time } = newQueue[head_bfs++];

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;
            const next_time = current_time + 1;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const [existing_color, existing_time] = finalState[nr][nc];

                // Case 1: Unreached cell (existing_time is Infinity)
                if (existing_time === Infinity) {
                    finalState[nr][nc] = [current_color, next_time];
                    newQueue.push({ r: nr, c: nc, color: current_color, time: next_time });
                    continue;
                }

                // Case 2: Reached at the same time
                if (next_time === existing_time) {
                    // Take the maximum color
                    if (current_color > existing_color) {
                        finalState[nr][nc] = [current_color, next_time];
                        // IMPORTANT: If we update the color at the same time, 
                        // this *new* color might spread further in the *same* time step
                        // if we were modeling propagation layer by layer. 
                        // However, the problem states: "所有扩散同时发生". 
                        // This implies we only care about the final state determined by the 
                        // arrival at T_new. Since we are using a queue based on time, 
                        // any cell processed at T+1 will propagate at T+2. 
                        // If we change the color at T_new, we don't need to re-add it to the queue
                        // for further expansion *from this step*, as it has already been processed 
                        // at this time level T_new in some sense, or its expansion will be 
                        // correctly handled when the T_new level is finished.
                        // Since we are propagating from the *source* cell (r, c) which arrived at T_old,
                        // and this neighbor (nr, nc) arrived at T_new, we only queue it if it was the *first* time
                        // it was colored. If it's being overwritten at the same time, no need to re-queue.
                    }
                } 
                // Case 3: Arrived earlier or later
                else if (next_time < existing_time) {
                    // We found a strictly faster path. Update and queue.
                    finalState[nr][nc] = [current_color, next_time];
                    newQueue.push({ r: nr, c: nc, color: current_color, time: next_time });
                } 
                // else (next_time > existing_time): Slower path, ignore.
            }
        }
    }

    // 3. Format output
    const result = Array(n).fill(0).map(() => Array(m).fill(0));
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            result[r][c] = finalState[r][c][0];
        }
    }

    return result;
}

